// // This D flip-flop captures the value of the data input (D) on the falling edge of the clock signal (clk) and holds it until the next falling edge. If the reset signal (rst) is low, the output (Q) is reset to 1.
module d_flip_flop(
    input clk,
    input rst,
    input D,

    output reg Q
);

always@(posedge clk or posedge rst)
begin

  if(rst)
  begin
    Q <= 0;
  end

  else
  begin
    Q <= D;
  end

end

endmodule
